import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MainMenu from './components/MainMenu';


function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<MainMenu />} />
        <Route path="/start-game" element={<h2>Start Game Page</h2>} />
        <Route path="/create-game" element={<h2>Create Game Page</h2>} />
        <Route path="/set-game" element={<h2>Set Game Page</h2>} />
        <Route path="/players" element={<h2>Players Setting Page</h2>} />
        <Route path="/history" element={<h2>History Page</h2>} />
      </Routes>
    </Router>
  );
}

export default App;
